import pickleform from "../components/form";



function Pickle(){
    return(
        <>
        
        <Navbar />
         <Hero 
         cName="hero-mid"
         heroImg = {OurTeamimg}
         title= ""

         />
        
       <Footer />
        </>
         
    )
}
export default Pickle;
